def analyze_function(func_code):
    """
    Analyze a function's code for common smells.
    Returns a list of issue strings.
    """
    issues = []
    lines = [l for l in func_code.split('\n') if l.strip() and not l.strip().startswith('#')]

    # TODO: Check 1 — Function too long (> 20 non-empty, non-comment lines)
    if len(lines) > 20:
        issues.append(f"Function too long: {len(lines)} lines (max 20)")

    # TODO: Check 2 — Too many parameters
    # Find the def line and count commas in parameter list
    def_line = next((l for l in func_code.split('\n') if l.strip().startswith('def ')), "")
    params = def_line.split('(')[1].split(')')[0].strip() if '(' in def_line else ""
    param_count = len([p for p in params.split(',') if p.strip()]) if params else 0
    # TODO: If param_count > 5, append issue

    # TODO: Check 3 — Deep nesting (count max indentation level)
    max_indent = 0
    for line in func_code.split('\n'):
        if line.strip():
            indent = (len(line) - len(line.lstrip())) // 4
            max_indent = max(max_indent, indent)
    # TODO: If max_indent > 4 (3 levels inside function), append issue

    return issues

# Test with clean and smelly functions
clean_func = """
def calculate_total(price, quantity, discount=0):
    subtotal = price * quantity
    if discount > 0:
        subtotal = subtotal * (1 - discount)
    return round(subtotal, 2)
"""

smelly_func = """
def process_data(a, b, c, d, e, f, g):
    result = []
    for item in a:
        if item > 0:
            for sub in b:
                if sub > 0:
                    for deep in c:
                        if deep:
                            result.append(deep * 42)
    x = 100
    y = 200
    z = x + y + 42
    return result
"""

print("Clean function issues:")
clean_issues = analyze_function(clean_func)
if clean_issues:
    for issue in clean_issues:
        print(f"  - {issue}")
else:
    print("  None")

print("\nSmelly function issues:")
smelly_issues = analyze_function(smelly_func)
for issue in smelly_issues:
    print(f"  - {issue}")

