from typing import Optional, List

def greet(name: str, times: int = 1) -> List[str]:
    return [f"Hello, {name}!" for _ in range(times)]

def find(items: List[int], target: int) -> Optional[int]:
    return next((i for i, x in enumerate(items) if x == target), None)

print(greet("Alice", 2))
print(find([1, 2, 3], 2))
print(find([1, 2, 3], 99))
